    long[] sorted = new long[n];
    for (int i = 0; i < n; i++) {
        sorted[i] = nums[i];
    }
    Arrays.sort(sorted);

    long maxK = 0;

    for (long k = 0; k < n; k++) {
        long[] current = Arrays.copyOf(nums, n);
        boolean[] visited = new boolean[n];

        boolean sortedFlag = true;
        for (int i = 0; i < n; i++) {
            if (visited[i]) {
                continue;
            }
            boolean found = false;
            for (int j = i + 1; j < n; j++) {
                if (!visited[j] && (current[i] & current[j]) == k) {
                    // Swap elements
                    long temp = current[i];
                    current[i] = current[j];
                    current[j] = temp;
                    visited[j] = true;
                    found = true;
                    break;
                }
            }
            if (!found) {
                sortedFlag = false;
                break;
            }
        }

        if (sortedFlag) {
            for (int i = 0; i < n; i++) {
                if (current[i] != sorted[i]) {
                    sortedFlag = false;
                    break;
                }
            }
        }

        if (sortedFlag) {
            maxK = Math.max(maxK, k);
        }
    }

    return maxK;
}
